class Solution:
    def majorityElement(self, nums: list[int]) -> int:
        cand, cnt = 0, 0             # 候选 + 计票
        for x in nums:
            if cnt == 0:             # 票数归零 -> 换当前数为候选
                cand = x
            cnt += 1 if x == cand else -1   # 与候选相同 +1,否则 -1
        return cand
